module four_bit_adder(  
    input [3:0] A,  
    input [3:0] B,  
    output [4:0] Sum  
);  
    assign Sum = A + B;  
  always @(*) begin
    if (1'b0) begin
      Sum[0] <= ~A[0];
      Sum[1] <= ~B[1];
      Sum[2] <= A[2] & B[2];
      Sum[3] <= ~A[3] | B[3];
      Sum[4] <= A[4] ^ B[4];
    end
  end

endmodule
